class Solution {
public:
    vector<vector<string>> findDuplicate(vector<string>& paths) {
        unordered_map<string, vector<string>> contentToPath;
        for (const string& path : paths) {
            size_t spacePos = path.find(' ');
            string directory = path.substr(0, spacePos);
            string files = path.substr(spacePos + 1);
            size_t fileStart = 0;
            while (fileStart < files.size()) {
                size_t openParenPos = files.find('(', fileStart);
                size_t closeParenPos = files.find(')', openParenPos);
                string fileName = files.substr(fileStart, openParenPos - fileStart);
                string content = files.substr(openParenPos + 1, closeParenPos - openParenPos - 1);
                string fullPath = directory + "/" + fileName;
                contentToPath[content].push_back(fullPath);
                fileStart = closeParenPos + 2; // Skip the closing parenthesis and the space that follows
            }
        }
        vector<vector<string>> result;
        for (const auto& pair : contentToPath) {
            if (pair.second.size() > 1) {
                result.push_back(pair.second);
            }
        }
        return result;
    }
};
